import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';

import { MarketplaceModuleParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/MarketplaceModuleParser';

export class MarketplaceModuleEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, MarketplaceModuleParser);
    }

    public getParser(): MarketplaceModuleParser {
        return this.parser as MarketplaceModuleParser;
    }
}
